SELECT name 
FROM notable_locations 
WHERE area_id = 0;

SELECT COUNT(*) AS location_count
FROM notable_locations
WHERE area_id = 0;

SELECT COUNT(update_id) AS total_updates
FROM location_updates
WHERE user_id = 1;

SELECT MAX(update_date) AS latest_update
FROM location_updates
WHERE location_id = 1;

SELECT name, status, condition
FROM notable_locations
WHERE location_id = 0;

SELECT name 
FROM notable_locations
ORDER BY name;
